const OPENAI_API_KEY = $env['OPENAI_API_KEY'];
const product = $input.first().json.product;
const topic = $input.first().json.topic;
const target_audience = $input.first().json.target_audience;

const SCRIPT_SYSTEM = `You are the creative director for @vitalessencehealth, a TikTok Shop brand selling premium health supplements and wellness products. Your job is to write short-form video scripts that feel authentic, personal, and emotionally resonant — not like ads.

BRAND VOICE:
- Confident but warm. Like a trusted friend who discovered something life-changing.
- Conversational, never clinical. No jargon, no buzzwords.
- Storytelling-first: the product is the solution, not the hero. The audience struggle is the hero.
- Never salesy. The CTA emerges naturally from the transformation story.

PRODUCT CONTEXT:
- vitamins: Daily foundational supplement stack. Focus on energy, mental clarity, filling nutritional gaps from modern diets, morning routine integration. Key emotion: I finally feel like myself again.
- gut_health: Digestive enzyme and probiotic blend. Focus on bloating relief, gut-brain connection, regularity, feeling light after meals, food freedom. Key emotion: I can finally eat without dreading what comes after.
- nobs_toothpaste: Toothpaste tablets — zero plastic, clean ingredients, travel-friendly. Focus on whiter teeth, fresh breath, clean beauty transition, sustainability. Key emotion: I did not know oral care could feel this good AND be this clean.

SCRIPT STRUCTURE — always follow this arc:
[HOOK 0-3s]: One punchy line. Creates pattern interrupt. Must stop the scroll.
[PROBLEM 3-10s]: Relate to the audience specific struggle. Be specific, be real.
[DISCOVERY 10-20s]: Finding @vitalessencehealth. Keep it organic, not a pitch.
[TRANSFORMATION 20-35s]: The results. Specific, sensory, believable.
[CTA 35-45s]: Soft close. Point to TikTok Shop link. One clear action.

SCENE MARKERS — tag each visual transition:
[SCENE 1] = Hook and Problem visual (relatable moment, person)
[SCENE 2] = Discovery and Product visual (product in lifestyle context)
[SCENE 3] = Transformation and CTA visual (results, confident person, product close-up)

OUTPUT FORMAT strict JSON no markdown no explanation:
{"voiceover": "<clean voiceover text only no stage directions 75-115 words>", "scenes": ["<Scene 1 visual description for image generation>", "<Scene 2 visual description for image generation>", "<Scene 3 visual description for image generation>"], "hook": "<first 1-2 sentences the scroll-stopping hook>", "cta": "<final 1-2 sentences the call to action>"}`;

const SCORER_SYSTEM = `You are a TikTok content quality judge for @vitalessencehealth, a health supplement brand. You evaluate short-form video scripts with ruthless honesty.

You score on exactly 5 criteria. Each criterion is scored 1-5.

SCORING CRITERIA:
1. HOOK STRENGTH (1-5) — 5 stops scroll immediately in under 3 seconds. 1 is generic and forgettable.
2. EMOTIONAL ARC QUALITY (1-5) — 5 is a clear believable problem to discovery to transformation journey. 1 is flat and reads like a feature list.
3. BRAND VOICE ACCURACY (1-5) — 5 sounds like a real person sharing a genuine discovery, warm, confident, health-focused. 1 sounds like a press release.
4. PRODUCT BENEFIT ACCURACY (1-5) — 5 has specific credible benefits matching the actual product. 1 has wrong or overclaimed benefits and compliance red flags.
5. CTA EFFECTIVENESS (1-5) — 5 flows naturally from the story with one clear action to shop. 1 has no clear CTA or it is confusing.

PASS THRESHOLD: Total score must be 18 or higher out of 25.

OUTPUT FORMAT strict JSON no markdown no explanation:
{"total_score": <number 5-25>, "pass": <true if total_score >= 18 otherwise false>, "feedback": "<2-3 sentences of specific actionable feedback>", "criteria_scores": {"hook_strength": <1-5>, "emotional_arc": <1-5>, "brand_voice": <1-5>, "product_accuracy": <1-5>, "cta_effectiveness": <1-5>}}`;

async function callOpenAI(messages, temperature, maxTokens) {
  const response = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${OPENAI_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'gpt-4o',
      messages: messages,
      temperature: temperature,
      max_tokens: maxTokens,
      response_format: { type: 'json_object' }
    })
  });
  const data = await response.json();
  if (!response.ok) throw new Error('OpenAI API error: ' + JSON.stringify(data.error || data));
  return JSON.parse(data.choices[0].message.content);
}

let attempt = 0;
let script = null;
let score = null;
let passed = false;

while (attempt < 3) {
  attempt++;
  script = await callOpenAI([
    { role: 'system', content: SCRIPT_SYSTEM },
    { role: 'user', content: `Write a TikTok script for @vitalessencehealth.\n\nProduct: ${product}\nTopic: ${topic}\nTarget Audience: ${target_audience}\n\nReturn strict JSON only.` }
  ], 0.85, 1000);

  score = await callOpenAI([
    { role: 'system', content: SCORER_SYSTEM },
    { role: 'user', content: `Score this TikTok script for @vitalessencehealth.\n\nProduct: ${product}\nTarget Audience: ${target_audience}\n\nScript: ${JSON.stringify(script)}\n\nReturn strict JSON only.` }
  ], 0.2, 600);

  if (score.pass === true) {
    passed = true;
    break;
  }
}

return [{ json: { script, score, passed, attempt_count: attempt, product, topic, target_audience } }];

const OPENAI_API_KEY = $env['OPENAI_API_KEY'];

const scriptData = $('Code - Script Gen + Score Loop').item.json;
const script = scriptData.script;
const score = scriptData.score;
const product = scriptData.product;
const topic = scriptData.topic;
const target_audience = scriptData.target_audience;
const attempt_count = scriptData.attempt_count;

// Get voiceover binary from ElevenLabs
const elevenlabsBinary = $input.first().binary;
const audioData = elevenlabsBinary?.voiceover_audio?.data || '';

const productStyleHints = {
  vitamins: 'health supplements, morning routine, supplement bottle with capsules, glass of water, natural wellness',
  gut_health: 'digestive health supplement, probiotic, gut wellness, fresh vegetables nearby, clean kitchen',
  nobs_toothpaste: 'toothpaste tablets, sustainable oral care, minimalist bathroom shelf, clean white teeth, eco-friendly tin'
};
const styleHint = productStyleHints[product] || 'health and wellness product';

const sceneStyleSuffixes = [
  'relatable everyday candid moment, warm natural window light, authentic lifestyle photography',
  'clean professional product photography, neutral or white background, soft studio lighting',
  'aspirational confident portrait, bright natural outdoor lighting, transformation energy'
];

async function generateImage(sceneDescription, styleSuffix) {
  const prompt = `${sceneDescription} | Style: photorealistic, TikTok vertical 9:16 format, health and wellness aesthetic, ${styleSuffix}, ${styleHint} | No text overlays, no logos, no watermarks`;
  const response = await fetch('https://api.openai.com/v1/images/generations', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${OPENAI_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'dall-e-3',
      prompt: prompt,
      n: 1,
      size: '1024x1792',
      quality: 'standard',
      response_format: 'b64_json'
    })
  });
  const data = await response.json();
  if (!response.ok) throw new Error('DALL-E error: ' + JSON.stringify(data.error || data));
  return data.data[0].b64_json;
}

const [scene01, scene02, scene03] = await Promise.all([
  generateImage(script.scenes[0], sceneStyleSuffixes[0]),
  generateImage(script.scenes[1], sceneStyleSuffixes[1]),
  generateImage(script.scenes[2], sceneStyleSuffixes[2])
]);

const line = '─'.repeat(48);
const scriptText = `VITALESSENCE TIKTOK CONTENT PACKAGE\n${'='.repeat(50)}\n\nProduct: ${product}\nTopic: ${topic}\nTarget Audience: ${target_audience}\nGenerated: ${new Date().toISOString()}\n\n${line}\nQUALITY SCORE REPORT\n${line}\nTotal Score: ${score.total_score}/25 (${score.pass ? 'PASSED' : 'FAILED'})\nAttempts to pass: ${attempt_count}\n\nCriteria Breakdown:\n  Hook Strength:     ${score.criteria_scores.hook_strength}/5\n  Emotional Arc:     ${score.criteria_scores.emotional_arc}/5\n  Brand Voice:       ${score.criteria_scores.brand_voice}/5\n  Product Accuracy:  ${score.criteria_scores.product_accuracy}/5\n  CTA Effectiveness: ${score.criteria_scores.cta_effectiveness}/5\n\nFeedback: ${score.feedback}\n\n${line}\nSCRIPT\n${line}\n\nHOOK (0-3s):\n${script.hook}\n\nFULL VOICEOVER:\n${script.voiceover}\n\nCTA:\n${script.cta}\n\n${line}\nSCENE IMAGE DESCRIPTIONS\n${line}\n[SCENE 1 - Hook/Problem]: ${script.scenes[0]}\n[SCENE 2 - Discovery/Product]: ${script.scenes[1]}\n[SCENE 3 - Transformation/CTA]: ${script.scenes[2]}\n`;

return [{
  json: {
    script,
    score,
    product,
    topic,
    target_audience,
    attempt_count,
    scriptText
  },
  binary: {
    voiceover_audio: {
      data: audioData,
      mimeType: 'audio/mpeg',
      fileName: 'voiceover.mp3'
    },
    scene_01: {
      data: scene01,
      mimeType: 'image/png',
      fileName: 'scene_01.png'
    },
    scene_02: {
      data: scene02,
      mimeType: 'image/png',
      fileName: 'scene_02.png'
    },
    scene_03: {
      data: scene03,
      mimeType: 'image/png',
      fileName: 'scene_03.png'
    }
  }
}];

